import{_ as t,o as r,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"血肉造物","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/2.D级/血肉造物.md","filePath":"4.资源分区/7.物品与装备/3.防具/2.D级/血肉造物.md"}'),p={name:"4.资源分区/7.物品与装备/3.防具/2.D级/血肉造物.md"};function d(l,a,_,i,c,h){return r(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"血肉造物",tabindex:"-1"},[s("血肉造物 "),e("a",{class:"header-anchor",href:"#血肉造物","aria-label":'Permalink to "血肉造物"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004")])])],-1),o('<h1 id="血肉造物-1" tabindex="-1">血肉造物 <a class="header-anchor" href="#血肉造物-1" aria-label="Permalink to &quot;血肉造物&quot;">​</a></h1><p>血肉造物</p><p>魔幻本质<br> D+1000</p><p>这是一具由不明血肉拼合而成的盔甲，被视为一件轻甲，但同时占据上肢和下肢位置。这团不定形状的血肉造物会随着穿戴者的意念而变化，从而施展它自身的能力。</p><p>血肉造物不会提供盔甲防御，在血肉造物即将抵御一次伤害时，盔甲表面会浮现出无数只鲜血淋漓的手，一齐合力抵挡攻击。血肉造物会提供5点格挡防御。</p><p>若穿戴者在穿戴时试图释放一道法术成分为语言的黑暗派系法术或【神话典籍记载法术】，血肉造物上将会自动变化出一张嘴用以吟诵而满足语言条件，而无需穿戴者自身满足。</p><p>每场影片结束后，穿戴者还可以仅一次从主神处再花费250分购买血肉用以喂养这团造物，若如此做，则血肉造物会再获得1点基于格挡防御的活体护甲。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=t(p,[["render",d]]);export{b as __pageData,m as default};
